head.script:
// 전역 변수
scwin.memJson = $c.data.getMemInfo();
scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;
scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd;
scwin.vUserHomeClsCd = scwin.memJson.userHomeClsCd;
scwin.vCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;
scwin.isSubCompany = false;
scwin.privAdmin = scwin.memJson.privAdmin;
scwin.txtCoClsCd = "";

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    scwin.params = $c.data.getParameter();
};

/**
 * UDC값
 */
scwin.onUdcCompleted = function() {
    if(!$c.util.isEmpty(scwin.params["standardBudgetYr"])) {
            ica_standardBudgetYr.setValue(scwin.params["standardBudgetYr"]);
    }

    if(!$c.util.isEmpty(scwin.params["coCd"])) {
            ed_coCd.setValue(scwin.params["coCd"]);
    }
    ica_targetBudgetYr.focus();
    scwin.f_PopUpCompanyInfo('T');
    $c.gus.cfDisableObjects([ed_coCd, ed_coNm]);
};

//-------------------------------------------------------------------------
// 생성 : 
//-------------------------------------------------------------------------
scwin.f_Create = async function() {
    //생성조건 입력여부 및 형식 체크
    let ret = await $c.gus.cfValidate([ica_standardBudgetYr,ica_targetBudgetYr]);
    if (!ret) {
        return false;
    }

    //반영할 년도와 기준년도가 같은 지 체크
    if (ica_standardBudgetYr.getValue().trim() == ica_targetBudgetYr.getValue().trim()) {
        await $c.win.alert("기준년도와 반영할 년도가 같습니다.");
        ica_targetBudgetYr.focus();
        return;
    }

    if (await $c.win.confirm("자동생성하시겠습니까?")) {
        dma_master.set("standardBudgetYr", ica_standardBudgetYr.getValue());
        dma_master.set("targetBudgetYr", ica_targetBudgetYr.getValue());
        dma_master.set("deleteYn", 0);
        dma_master.set("coCd", ed_coCd.getValue());

        $c.sbm.execute(sbm_master);
    }
};

// -------------------------------------------------------------------------
// 회사 입력 팝업 
// -------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function(pWinCloseTF) {
	await udc_dongbuGroupCompanyInfo.cfCommonPopUp(scwin.udc_dongbuGroupCompanyInfo_callBackFunc,
							ed_coCd.getValue(), ""
							,pWinCloseTF,null,null,null,null
							,null,null,null,null,null);   
}

scwin.udc_dongbuGroupCompanyInfo_callBackFunc = function(rtnList) {
	// SET	 
	if(rtnList != null ) { 
		if (rtnList[0] == "N/A") return; 

		ed_coCd.setValue(rtnList[0]);	// 코드
		ed_coNm.setValue(rtnList[5]); // 회사명  		
	}else{
        ed_coCd.setValue("");
        ed_coNm.setValue("");
	}

	if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU)  {  	// 자회사 회계 시스템 
		scwin.isSubCompany = true;
	}else{
		scwin.isSubCompany = false;
	}
};

scwin.sbm_master_submitdone = async function (e) {
    if(ds_result.getCellData(0,"deleteYn") == 1) {
    	await $c.win.alert(MSG_CM_INF_002);

        $c.win.closePopup();
    } else {
        if(await $c.win.confirm("반영할 년도에 기존 데이터가 존재합니다.\n 삭제하시고 자동생성하시겠습니까?")==true){
		  	dma_master.set("standardBudgetYr",ica_standardBudgetYr.getValue());
		  	dma_master.set("targetBudgetYr",ica_targetBudgetYr.getValue());
		  	dma_master.set("deleteYn",1);
		  	dma_master.set("coCd",ed_coCd.getValue());

		  	$c.sbm.execute(sbm_master);
        }
 	}
};

scwin.ed_coCd_onblur = function (e) {
    scwin.f_PopUpCompanyInfo();
};

scwin.btn_close_onclick = function (e) {
    $c.win.closePopup();
};
